import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch16: ScenarioQuestion[] = [
  q("sq-bg16-1",ip,"clinical_judgment","A patient develops esophageal varices bleeding.","How would you manage variceal hemorrhage?","Variceal bleeding is a life-threatening complication of portal hypertension. I would establish two large-bore IVs, initiate volume resuscitation, administer octreotide IV to reduce portal pressure, prepare for emergent endoscopy with band ligation, administer prophylactic antibiotics (ceftriaxone), and avoid over-resuscitation that increases portal pressure.","Variceal hemorrhage with octreotide and band ligation.","advanced"),
  q("sq-bg16-2",ip,"clinical_judgment","A patient develops malignant pleural effusion.","How would you manage malignant pleural effusion?","Malignant pleural effusion presents with progressive dyspnea in cancer patients. Therapeutic thoracentesis provides immediate relief. For recurrent effusions, pleurodesis (talc or doxycycline) prevents re-accumulation, or an indwelling pleural catheter allows ongoing drainage at home. I would position the patient upright, monitor for respiratory improvement, and limit drainage to 1500mL to prevent re-expansion pulmonary edema.","Malignant effusion with re-expansion prevention.","intermediate"),
  q("sq-bg16-3",ip,"clinical_judgment","A patient develops acute pancreatitis.","How would you manage acute pancreatitis?","Acute pancreatitis presents with epigastric pain radiating to the back, elevated lipase (>3x normal), and possible Cullen or Grey Turner signs in severe cases. Management includes aggressive IV fluid resuscitation (250-500mL/hr initially), pain management, NPO initially then early enteral nutrition when tolerated, and monitoring for organ failure using the BISAP or Ranson criteria.","Acute pancreatitis aggressive hydration and early feeding.","intermediate"),
  q("sq-bg16-4",ip,"clinical_judgment","A patient develops hypertrophic cardiomyopathy obstruction during exercise.","How does HOCM obstruction present?","HOCM causes dynamic LVOT obstruction worsened by: Valsalva, standing, dehydration, and exercise. It presents with exertional syncope, dyspnea, and a systolic murmur that increases with standing and Valsalva. Treatment includes beta-blockers, avoiding dehydration, no digoxin or vasodilators (worsen obstruction), and avoiding strenuous exercise. ICD may be needed for high-risk patients.","HOCM with obstruction-worsening factors.","advanced"),
  q("sq-bg16-5",ip,"clinical_judgment","A patient develops acute mesenteric ischemia.","How would you recognize acute mesenteric ischemia?","Acute mesenteric ischemia presents with severe abdominal pain out of proportion to physical findings—the classic pain-examination disconnect. CT angiography confirms the diagnosis. Risk factors include AFib, atherosclerosis, and low-flow states. This is a vascular emergency requiring emergent revascularization or bowel resection. Delayed diagnosis leads to bowel necrosis and death.","Mesenteric ischemia pain-exam disconnect.","advanced"),
  q("sq-bg16-6",ip,"behavioral","You are asked about your commitment to nursing.","What keeps you committed to nursing?","I am committed because nursing offers the rare opportunity to make a tangible difference in someone's most vulnerable moments. Every shift brings new challenges that keep me growing. The combination of scientific knowledge and human connection is uniquely fulfilling. I cannot imagine a more purposeful career.","Purpose-driven nursing commitment.","beginner"),
  q("sq-bg16-7",ip,"scenario_responses","A patient is anxious about an upcoming test result.","How would you support a patient waiting for results?","I would acknowledge the anxiety: 'Waiting for results is one of the hardest parts. While I cannot predict the outcome, I can tell you that whatever the results show, your care team will have a plan. Is there anything I can help you with while you wait? Sometimes talking through what different outcomes might mean can help you feel more prepared.'","Test result anxiety support.","beginner"),
  q("sq-bg16-8",ip,"star_examples","Describe a time you recognized a patient deterioration early.","Share an early deterioration recognition example.","I noticed my patient's respiratory rate increased from 16 to 24 over 2 hours while other vitals remained stable. Instead of attributing it to anxiety, I performed a focused respiratory assessment, found new crackles, and notified the physician. The chest X-ray revealed early pulmonary edema. Early intervention with diuretics prevented intubation. The subtle change in respiratory rate was the only early warning sign.","Subtle respiratory rate trend recognition.","intermediate"),
  q("sq-bg16-9",ws,"prioritization","Three patients call at once: one is nauseated, one fell, one has chest pain.","How would you prioritize three simultaneous calls?","Chest pain first—potential cardiac emergency requiring immediate assessment. Fall second—need to assess for injury, especially head injury or fracture. Nausea third—concerning but usually not immediately life-threatening. I would delegate: ask a colleague to address the fall patient while I assess chest pain, then address nausea after stabilizing the first two.","Triple simultaneous call triage.","beginner"),
  q("sq-bg16-10",ws,"delegation","You need to delegate ambulation for a post-surgical patient.","How would you delegate first post-operative ambulation?","I would specify: 'This is Mr. Chen's first time walking after his hip replacement. Use the walker, stay within arm's reach, walk only to the doorway and back today. Watch for dizziness when standing—have him sit on the bed edge for 2 minutes first. If he reports pain greater than 5/10 or dizziness, return him to bed and notify me immediately.'","Post-surgical first ambulation delegation.","beginner"),
  q("sq-bg16-11",ws,"patient_safety","A patient develops central line infection.","How would you help prevent CLABSI?","CLABSI prevention includes: daily line necessity assessment, chlorhexidine bathing, hand hygiene before and after line access, scrub the hub for 15 seconds before each access, sterile dressing changes per protocol, and prompt removal of unnecessary lines. Each unnecessary line day increases infection risk. Nurse-driven line removal protocols reduce CLABSI rates significantly.","CLABSI prevention with daily necessity assessment.","beginner"),
  q("sq-bg16-12",ws,"handoff_communication","A patient has been declining slowly over the shift.","How would you communicate a slow decline during handoff?","I would highlight the trend: 'Mrs. Adams has shown a gradual decline throughout the shift. Blood pressure trending down from 130 to 105 systolic, heart rate up from 78 to 96, urine output decreasing. No single vital sign is alarming, but the overall trend concerns me. I have notified Dr. Garcia who is aware and following. Please continue trending closely.'","Subtle decline trend handoff emphasis.","intermediate"),
  q("sq-bg16-13",ws,"difficult_coworkers","A colleague consistently takes long breaks, leaving you to cover.","How would you address a colleague's excessive break time?","I would address it directly: 'I have noticed that your breaks often extend beyond the scheduled time, which means I am covering your patients longer than expected. This affects my ability to manage my own patient care safely. Can we agree on a reliable break schedule that works for both of us?' If the behavior continues, I would involve the charge nurse.","Excessive break time direct address.","beginner"),
  q("sq-bg16-14",ct,"first_shift","You are learning to manage a patient with a chest tube.","How would you safely manage a chest tube?","I would ensure the drainage system is below the chest level, check for tidaling (fluctuation with breathing—indicates patency), monitor drainage color, consistency, and volume, assess for air leaks in the water seal chamber, keep petroleum gauze at the bedside for accidental dislodgement, and never clamp a chest tube without a physician order.","Chest tube management fundamentals.","beginner"),
  q("sq-bg16-15",ct,"new_nurse_anxiety","You feel like imposter syndrome is affecting your confidence.","How would you manage imposter syndrome?","I would recognize that imposter syndrome affects 70% of professionals at some point. I would document my accomplishments, accept compliments without deflecting, acknowledge that competence develops over time, find a mentor who normalizes the learning curve, and remind myself that feeling like an imposter actually correlates with conscientiousness—which makes me a safer nurse.","Imposter syndrome normalization.","beginner"),
  q("sq-bg16-16",ct,"time_management","You are constantly running behind on your assessments.","How would you improve assessment efficiency?","I would develop a systematic head-to-toe approach that I perform the same way every time, reducing cognitive load. I would set specific times for each patient's assessment, cluster assessment with medication administration, use a focused assessment for stable patients and full assessment for new or changing patients, and document findings in real-time.","Assessment efficiency through systematic approach.","beginner"),
  q("sq-bg16-17",ct,"documentation_challenges","You need to document a code blue event.","How would you document code documentation effectively?","I would use the designated code documentation form with exact timestamps: code called, CPR initiated, defibrillation attempts (times, joules, rhythms), medications given (drug, dose, route, time), intubation (time, tube size, confirmation method), rhythm changes, ROSC or time of death, team leader and participants, and family notification.","Code documentation precise timeline.","intermediate"),
  q("sq-bg16-18",ct,"critical_thinking_drills","A patient's ABG shows pH 7.50, PCO2 28, HCO3 24.","How would you interpret this ABG?","pH 7.50 is alkalotic, PCO2 28 is low (respiratory alkalosis), HCO3 24 is normal (no metabolic compensation yet). This is acute respiratory alkalosis from hyperventilation. Causes include anxiety, pain, PE, early sepsis, and salicylate toxicity. I would assess the patient for the cause, address anxiety or pain, and check for PE if clinically indicated.","Acute respiratory alkalosis interpretation.","beginner"),
  q("sq-bg16-19",pd,"professional_boundaries","A patient offers to set you up on a date with their child.","How would you decline a personal matchmaking offer?","I would decline warmly: 'That is very kind of you to think of me. However, I need to keep our relationship professional to provide you with the best care possible. I appreciate the thought, though.' Maintaining boundaries does not require harshness—a warm but clear decline preserves both the therapeutic relationship and professional integrity.","Matchmaking offer warm professional decline.","beginner"),
  q("sq-bg16-20",pd,"ethical_dilemmas","A terminally ill patient asks you to increase their morphine to end their life.","How would you respond to a request for euthanasia?","I would address the suffering: 'I hear that your suffering is overwhelming. While I cannot intentionally end your life, I can ensure you receive the best possible comfort care. Let me contact our palliative care team—they specialize in managing even the most severe symptoms. You do not have to suffer like this.' I would document the request and notify the physician.","Euthanasia request suffering-focused response.","advanced"),
  q("sq-bg16-21",pd,"advocacy","A patient with mental illness is being treated differently by staff.","How would you advocate against mental health stigma?","I would address it directly: 'I have noticed comments about our patient's psychiatric diagnosis that influence how we approach their care. Mental illness is a medical condition that deserves the same compassionate, evidence-based care as any other diagnosis. Our patient deserves to be treated with the same dignity and respect as every patient on this unit.'","Mental health stigma direct confrontation.","intermediate"),
  q("sq-bg16-22",pd,"patient_communication","A patient has just been diagnosed with a chronic disease.","How would you support a new chronic disease diagnosis?","I would provide space for the emotional response: 'This is a lot to process. There is no right way to feel right now. When you are ready, I want you to know that people live full, meaningful lives with this condition. We will build a management plan together, step by step. You do not have to figure everything out today.'","Chronic disease diagnosis emotional support.","beginner"),
  q("sq-bg16-23",cn,"job_offer_negotiation","You want to understand relocation assistance.","What should you know about relocation packages?","I would evaluate: moving cost coverage (full or partial), temporary housing duration, signing bonus versus relocation allowance, repayment requirements if you leave early, spousal job search assistance, and house-hunting trip coverage. Relocation costs can exceed $10,000—negotiating assistance is reasonable for positions requiring geographic relocation.","Relocation package evaluation.","beginner"),
  q("sq-bg16-24",cn,"probation_period","You want to develop a relationship with your charge nurse.","How would you build rapport with the charge nurse?","I would be reliable, communicate proactively about patient concerns, offer to help when my work is done, ask for assignment feedback, respect their experience and decision-making, and express appreciation for their support. The charge nurse is a critical ally during your first year—a positive relationship improves your experience and professional development.","Charge nurse rapport building.","beginner"),
  q("sq-bg16-25",cn,"career_advancement","You want to understand the value of precepting.","Why should nurses pursue preceptor roles?","Precepting develops leadership, teaching, and communication skills while contributing to the profession. It deepens your own clinical knowledge (teaching reinforces learning), demonstrates leadership readiness, often includes financial incentives, and helps shape the next generation of nurses. Most leadership positions require precepting experience.","Preceptor role value and development.","beginner"),
  q("sq-bg16-26",cn,"performance_evaluation","You want to showcase patient safety contributions.","How would you demonstrate safety contributions during evaluation?","I would present: 'I caught 3 medication discrepancies during medication reconciliation, identified a deteriorating patient 4 hours before clinical deterioration criteria were met, initiated a falls prevention project that reduced our unit falls by 20%, and served on the patient safety committee where I implemented bedside handoff for our unit.'","Safety contribution with specific metrics.","beginner"),
  q("sq-bg16-27",ip,"clinical_judgment","A patient develops tension pneumothorax.","How would you recognize tension pneumothorax?","Tension pneumothorax is immediately life-threatening: absent breath sounds on affected side, tracheal deviation away from affected side, hypotension, distended neck veins, and cardiovascular collapse. Treatment is immediate needle decompression at the 2nd intercostal space, midclavicular line, followed by chest tube insertion. Do not wait for chest X-ray if clinical suspicion is high.","Tension pneumothorax needle decompression urgency.","advanced"),
  q("sq-bg16-28",ws,"interdisciplinary_communication","Multiple providers have different discharge instructions for the same patient.","How would you resolve conflicting discharge instructions?","I would compile all instructions, identify conflicts, and present to the primary physician: 'We have conflicting discharge instructions—cardiology says resume aspirin immediately while surgery says hold for 2 weeks. Can we clarify the correct plan before I educate the patient? Conflicting instructions at discharge contribute to readmissions.'","Conflicting discharge instruction resolution.","beginner"),
  q("sq-bg16-29",ct,"critical_thinking_drills","A patient's troponin is rising in a stepwise pattern.","What does a rising troponin trend indicate?","A rising troponin pattern (delta troponin positive) strongly suggests acute myocardial injury, most commonly acute MI. A rising and falling pattern is typical of acute MI, while a chronically stable mild elevation suggests non-ischemic causes (CKD, heart failure). Serial troponin measurements with timing are more diagnostic than single values.","Troponin rise-and-fall pattern interpretation.","intermediate"),
  q("sq-bg16-30",pd,"advocacy","A patient needs assistance applying for disability benefits.","How would you help a patient access disability resources?","I would involve social work for disability application assistance, ensure medical documentation supports the disability claim, provide the patient with information about legal aid organizations that help with disability appeals, connect with community resources for interim support during the application process, and document functional limitations that support the claim.","Disability benefit application support.","beginner"),
  q("sq-bg16-31",ip,"clinical_judgment","A patient develops Ogilvie syndrome.","What is Ogilvie syndrome?","Ogilvie syndrome (acute colonic pseudo-obstruction) presents with massive colonic dilation without mechanical obstruction, typically in hospitalized patients. Cecal diameter >12cm risks perforation. Treatment includes neostigmine IV (with cardiac monitoring), decompression colonoscopy, and correcting underlying factors (electrolytes, medications, mobility). I would monitor abdominal girth and serial X-rays.","Ogilvie syndrome with perforation risk monitoring.","advanced"),
  q("sq-bg16-32",ws,"patient_safety","A patient develops hyperkalemia with ECG changes.","How would you manage hyperkalemia with ECG changes?","ECG changes (peaked T waves, widened QRS, sine wave) indicate cardiac toxicity requiring immediate treatment: calcium gluconate IV for cardiac membrane stabilization (works in 1-3 minutes), insulin plus dextrose to shift potassium intracellularly, sodium bicarbonate if acidotic, albuterol nebulizer, and kayexalate or patiromer for actual potassium removal. Continuous cardiac monitoring is essential.","Hyperkalemia emergency treatment sequence.","intermediate"),
  q("sq-bg16-33",ct,"documentation_challenges","You need to document a skin assessment finding.","How would you document a new skin finding?","I would document: location using anatomical landmarks, size in centimeters, color, shape, borders, elevation, texture, surrounding skin condition, temperature comparison, any associated symptoms (pain, itching), duration if known, and nursing interventions implemented. I would photograph per facility policy and notify the provider of new or changing skin findings.","Skin finding descriptive documentation.","beginner"),
  q("sq-bg16-34",pd,"patient_communication","A patient is having difficulty coping with cancer treatment side effects.","How would you support a patient struggling with chemo side effects?","I would validate their experience: 'Treatment side effects can be overwhelming. Your body is working hard, and what you are feeling is real. Let me help manage these symptoms—there are many interventions we have not tried yet. Antiemetics, nutrition adjustments, and supportive therapies can make a significant difference. You do not have to tough this out alone.'","Cancer treatment side effect empathetic support.","intermediate"),
  q("sq-bg16-35",cn,"career_advancement","You want to understand the emerging role of genetics in nursing.","How will genomics change nursing practice?","Genomic nursing will require understanding: pharmacogenomics (drug metabolism variations), genetic testing implications, hereditary disease risk counseling, precision medicine approaches, and ethical considerations of genetic information. The future nurse will use genetic data to personalize care plans, predict drug responses, and identify disease risk before symptoms appear.","Genomic nursing future impact.","intermediate"),
  q("sq-bg16-36",ip,"clinical_judgment","A patient develops posterior reversible encephalopathy syndrome.","How is PRES diagnosed and managed?","PRES shows characteristic posterior white matter edema on MRI with seizures, headache, visual changes, and altered consciousness. Causes include severe hypertension, eclampsia, immunosuppressants (tacrolimus, cyclosporine), and renal failure. Treatment addresses the underlying cause: blood pressure control, seizure management, and removing offending medications. PRES is reversible with prompt treatment.","PRES MRI findings and reversibility.","advanced"),
  q("sq-bg16-37",ws,"medication_error","A patient questions a medication change they were not informed about.","How would you handle an uninformed medication change?","I would investigate the change, verify it was ordered intentionally, and explain: 'I apologize that you were not informed about this change. Your physician changed your blood pressure medication because [reason]. Let me explain what the new medication does and why it was chosen. You have every right to be informed about changes to your treatment.'","Uninformed medication change patient explanation.","beginner"),
  q("sq-bg16-38",ct,"new_nurse_anxiety","You feel like your nursing education was more theoretical than practical.","How would you bridge the theory-practice gap?","I would actively seek hands-on opportunities during orientation, ask my preceptor to explain the clinical reasoning behind every decision, practice skills in simulation if available, use clinical reference apps for real-time drug and procedure information, and accept that the theory-practice gap is a universal experience that closes with each patient encounter.","Theory-practice gap active bridging.","beginner"),
  q("sq-bg16-39",pd,"ethical_dilemmas","You are asked to care for a patient whose values conflict with yours.","How would you provide care to someone whose beliefs conflict with yours?","I would provide the same standard of care regardless of personal value conflicts. My professional obligation is to the patient, not to my personal beliefs. If the conflict is so profound it affects my care quality, I would request reassignment and discuss with my supervisor. I would never allow personal judgment to compromise professional care standards.","Value conflict professional care commitment.","intermediate"),
  q("sq-bg16-40",cn,"career_advancement","You want to create lasting positive change in healthcare.","What systemic changes can nurses drive?","Nurses can drive: evidence-based protocol implementation, staffing ratio legislation, workplace violence prevention policies, patient safety culture improvements, health equity initiatives, interprofessional education reform, and nursing scope of practice expansion. Individual nurses change individual patient outcomes; nurse leaders change systems that affect millions of patients.","Systemic nursing change impact.","beginner"),
  q("sq-bg16-41",ip,"clinical_judgment","A patient develops cardiac arrest with PEA.","How would you manage pulseless electrical activity?","PEA shows organized electrical activity on the monitor without a pulse. I would initiate CPR, administer epinephrine 1mg IV every 3-5 minutes, and systematically search for reversible causes using the Hs and Ts: Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/Hyperkalemia, Hypothermia, Tension pneumothorax, Tamponade, Toxins, Thrombosis (PE and MI).","PEA ACLS with Hs and Ts differential.","advanced"),
  q("sq-bg16-42",ws,"patient_safety","A patient develops hyperthermia from environmental exposure.","How would you manage heatstroke?","Heatstroke (core temp >104°F with CNS dysfunction) is a medical emergency. I would remove the patient from the heat, initiate aggressive cooling: cold water immersion is most effective, or apply ice packs to groin, axillae, and neck, administer cold IV fluids, and monitor core temperature continuously. Stop cooling at 101-102°F to prevent overshoot hypothermia.","Heatstroke aggressive cooling with overshoot prevention.","intermediate"),
  q("sq-bg16-43",ct,"critical_thinking_drills","A patient's CRP is 150 mg/L.","What does markedly elevated CRP indicate?","CRP of 150 (normal <10) indicates significant systemic inflammation. CRP rises within 6-8 hours of inflammatory insult and doubles every 8 hours. Values >100 strongly suggest bacterial infection. CRP is more responsive than ESR for acute monitoring. I would correlate with clinical presentation, assess for infection sources, and trend CRP to monitor treatment response.","CRP as acute inflammation marker with trending.","beginner"),
  q("sq-bg16-44",pd,"advocacy","A patient with chronic pain is being undertreated due to stigma.","How would you advocate for a stigmatized chronic pain patient?","I would advocate with data: 'This patient has documented chronic pain from lumbar stenosis with MRI findings. They are not seeking inappropriate medication—they are seeking adequate pain management for a verified condition. Under-treating pain is also a quality-of-care concern. Can we develop a comprehensive pain management plan including non-pharmacological approaches?'","Chronic pain stigma evidence-based advocacy.","intermediate"),
  q("sq-bg16-45",cn,"career_advancement","You want to mentor the next generation of nurses.","How would you become an effective nurse mentor?","I would develop mentorship skills: active listening, providing balanced feedback, sharing experiences including failures, connecting mentees with resources and opportunities, setting clear expectations, celebrating growth, and being genuinely invested in their success. The best mentors do not create followers—they develop future leaders who surpass them.","Effective mentorship philosophy and skills.","beginner"),
  q("sq-bg16-46",ip,"clinical_judgment","A patient develops acute pulmonary edema.","How would you manage flash pulmonary edema?","Flash pulmonary edema presents with sudden severe dyspnea, pink frothy sputum, and hypoxemia. I would sit the patient upright, administer high-flow oxygen (CPAP/BiPAP if available), give IV furosemide for rapid diuresis, nitroglycerin for preload and afterload reduction, and morphine cautiously for anxiety and dyspnea. Identify and treat the trigger: ACS, hypertensive crisis, or valvular emergency.","Flash pulmonary edema LMNOP treatment.","advanced"),
  q("sq-bg16-47",ws,"handoff_communication","A patient is being transferred to another facility.","What information is essential for inter-facility transfer?","I would communicate: transfer reason, current clinical status, recent vital sign trends, active problems and treatments, medication list with last doses, pending tests and results, code status, allergies, isolation precautions, pertinent social history, family contact information, and copies of relevant imaging and lab results. Missing information during transfers causes adverse events.","Inter-facility transfer comprehensive communication.","intermediate"),
  q("sq-bg16-48",ct,"time_management","You are learning to be efficient with medication administration.","How would you improve medication pass efficiency?","I would review all medications before starting, identify timing-critical medications first, prepare medications for each patient completely before going to the room, bring the scanner and supplies in one trip, assess the patient during medication administration to cluster care, and document in real-time at the bedside. Preparation reduces interruptions.","Medication pass efficiency optimization.","beginner"),
  q("sq-bg16-49",pd,"professional_boundaries","A patient wants to add you to their prayer list at church.","How would you respond to a patient's prayer list request?","I would accept graciously: 'That is very thoughtful. I appreciate you thinking of me.' Being included in a patient's prayers is a meaningful gesture that respects boundaries—it does not require personal information exchange or ongoing contact. I would recognize that spiritual care often flows in both directions and that patients find comfort in giving as well as receiving.","Prayer list appropriate acceptance.","beginner"),
  q("sq-bg16-50",cn,"career_advancement","You want to understand nursing's role in artificial intelligence.","How will AI change nursing practice?","AI will augment nursing through: clinical decision support systems, predictive analytics for patient deterioration, automated documentation assistance, medication interaction checking, population health management, and precision medicine. Nurses who understand AI capabilities and limitations will be essential for ensuring technology enhances rather than replaces the human elements of care.","AI in nursing augmentation role.","intermediate"),
  q("sq-bg16-51",ip,"clinical_judgment","A patient develops infective endocarditis.","How would you recognize infective endocarditis?","IE presents with persistent fever, new or changing heart murmur, embolic phenomena (Janeway lesions, Osler nodes, splinter hemorrhages), and positive blood cultures. Duke criteria guide diagnosis. Treatment requires prolonged IV antibiotic therapy (4-6 weeks). I would monitor for complications: heart failure, stroke, septic emboli, and abscess formation.","Infective endocarditis Duke criteria recognition.","advanced"),
  q("sq-bg16-52",ws,"patient_safety","A patient is at high risk for venous thromboembolism.","How would you implement VTE prophylaxis?","I would assess VTE risk using validated tools, implement pharmacological prophylaxis (LMWH or UFH) unless contraindicated, ensure mechanical prophylaxis (SCDs) is applied and functioning, encourage early ambulation, maintain hydration, and reassess risk daily. VTE is a leading cause of preventable hospital death. Nurse-driven VTE assessment protocols improve prophylaxis compliance.","VTE prophylaxis comprehensive implementation.","beginner"),
  q("sq-bg16-53",ct,"documentation_challenges","You need to document informed consent.","How would you document the informed consent process?","I would document: 'Informed consent obtained by Dr. [name] at [time]. Procedure: [specific procedure]. Patient verbalized understanding of: the procedure, expected benefits, risks including [specific risks discussed], alternatives, and right to withdraw consent. Patient had opportunity to ask questions. No coercion. Patient signed consent form. Witness: [name, credentials].'","Informed consent documentation checklist.","beginner"),
  q("sq-bg16-54",pd,"patient_communication","A patient is overwhelmed by their treatment regimen.","How would you simplify a complex treatment regimen?","I would break it into manageable components: 'I know this feels overwhelming. Let us focus on the three most important things right now: take this medication every morning, check your blood sugar before meals, and walk for 15 minutes daily. Once these become routine, we will add the next steps. You do not have to master everything at once.'","Treatment regimen simplification strategy.","beginner"),
  q("sq-bg16-55",cn,"career_advancement","You want to plan your first year strategically.","What should you accomplish in your first year of nursing?","First year priorities: complete orientation successfully, achieve clinical competence with common diagnoses, build relationships with the interdisciplinary team, develop efficient time management, learn the facility's culture and processes, begin specialty certification study, participate in at least one committee, and establish a professional development plan. Year one builds the foundation for everything that follows.","First year strategic accomplishment plan.","beginner"),
  q("sq-bg16-56",ip,"clinical_judgment","A patient develops necrotizing fasciitis.","How would you recognize necrotizing fasciitis?","Necrotizing fasciitis presents with pain disproportionate to appearance, rapidly spreading erythema, skin that progresses from red to purple to black, crepitus, and systemic toxicity. This is a surgical emergency—delayed debridement is fatal. I would administer broad-spectrum antibiotics and ensure emergent surgical consultation. The LRINEC score helps assess probability.","Necrotizing fasciitis pain-appearance disconnect.","advanced"),
  q("sq-bg16-57",ws,"delegation","You need to delegate monitoring a patient after procedural sedation.","How would you delegate post-sedation monitoring?","I cannot delegate the initial post-sedation assessment—this requires RN-level monitoring. Once the patient meets discharge criteria (Aldrete score ≥9), I can delegate ongoing vital sign monitoring: 'Check vitals every 15 minutes for the next hour. The patient should be alert and able to swallow. Call me if drowsiness increases, oxygen saturation drops below 95%, or any new symptoms develop.'","Post-sedation monitoring scope-appropriate delegation.","intermediate"),
  q("sq-bg16-58",ct,"critical_thinking_drills","A patient's base excess is -8.","What does a negative base excess indicate?","Base excess of -8 (normal -2 to +2) indicates metabolic acidosis—the body has an excess of acid or deficit of base. Combined with clinical context: negative base excess in trauma suggests hemorrhage; in sepsis suggests tissue hypoperfusion; in DKA suggests ketoacid accumulation. Serial base excess monitoring tracks resuscitation adequacy.","Base excess as metabolic acidosis quantifier.","intermediate"),
  q("sq-bg16-59",pd,"ethical_dilemmas","A family wants to withhold a terminal diagnosis from their elderly parent.","How would you navigate family request to withhold diagnosis?","I would explore their concern: 'I understand you want to protect your parent. However, most patients sense something is wrong and withholding information can increase anxiety and undermine trust. Research shows most patients want to know their diagnosis. Would you be open to discussing how we can share this information in a compassionate, supportive way?'","Diagnosis disclosure family mediation.","intermediate"),
  q("sq-bg16-60",cn,"career_advancement","You want to understand the impact of nursing shortage.","How does the nursing shortage affect new graduates?","The nursing shortage creates both opportunities and risks for new graduates: opportunities include competitive salaries, sign-on bonuses, specialty choice flexibility, and rapid advancement. Risks include inadequate orientation due to staffing pressure, excessive workloads, insufficient mentorship, and pressure to function beyond competence level. New graduates should prioritize quality orientation over financial incentives.","Nursing shortage dual impact for new grads.","beginner"),
  q("sq-bg16-61",ip,"clinical_judgment","A patient develops hypovolemic shock from hemorrhage.","How would you manage hemorrhagic shock?","I would follow the ABCs: ensure airway, provide supplemental oxygen, establish two large-bore IVs, initiate massive transfusion protocol (1:1:1 ratio of PRBCs:FFP:platelets), apply direct pressure to visible bleeding, avoid excessive crystalloid (dilutional coagulopathy), permissively hypotense (SBP 80-90) until surgical control, and prepare for emergent surgical intervention.","Hemorrhagic shock with 1:1:1 and permissive hypotension.","advanced"),
  q("sq-bg16-62",ws,"patient_safety","A patient on seizure precautions has a seizure.","How would you manage an active seizure?","I would protect the patient from injury: lower the bed, remove nearby objects, turn to the side to prevent aspiration, do NOT restrain or put anything in their mouth, time the seizure, note the type and progression, administer lorazepam if ordered and seizure continues beyond 5 minutes, and call for help. After the seizure, assess neurological status and protect the airway.","Active seizure safe management.","beginner"),
  q("sq-bg16-63",ct,"time_management","You need to manage your time during a code situation.","How would you manage time during a code?","During a code, I would focus on my assigned role (compressions, medications, documentation, or airway), communicate clearly with the team leader, keep track of medication timing (epinephrine every 3-5 minutes), note rhythm check times, and document all interventions with exact times. After the code, I would complete thorough documentation while events are fresh.","Code situation time and role management.","intermediate"),
  q("sq-bg16-64",pd,"workplace_bullying","A nurse manager creates a hostile work environment.","How would you document a hostile work environment?","I would document: dates, specific behaviors, witnesses, impact on my work and patient care, and any prior attempts to address the issue. I would report through the chain of command to the next-level manager and HR simultaneously. I would keep personal copies of all documentation, use factual language without emotional characterization, and consider consulting the state nursing board if patient safety is affected.","Hostile environment systematic documentation.","intermediate"),
  q("sq-bg16-65",cn,"probation_period","You want to demonstrate readiness for independent practice.","How would you show you are ready for independent practice?","I would demonstrate: consistent safe medication administration, independent patient assessment with appropriate escalation, effective time management completing tasks within shift, confident but appropriate communication with physicians, accurate and timely documentation, delegation skills, and the ability to prioritize multiple patient needs simultaneously. Readiness is demonstrated daily, not declared.","Independent practice readiness demonstration.","beginner"),
  q("sq-bg16-66",ip,"clinical_judgment","A patient develops hyperosmolar hyperglycemic state.","How does HHS management differ from DKA?","HHS involves more severe dehydration (often 9+ liters deficit) than DKA, requiring more aggressive and prolonged fluid resuscitation. HHS has minimal ketosis, so bicarbonate is not needed. Insulin doses are typically lower. The mortality rate is higher (10-20% vs 1-5% for DKA) because HHS patients are often elderly with significant comorbidities.","HHS versus DKA management differences.","advanced"),
  q("sq-bg16-67",ws,"handoff_communication","A patient is transitioning from ICU to floor.","What is critical for ICU-to-floor step-down handoff?","I would include: reason for ICU admission and current resolution, downgraded from which level of monitoring, current vital sign parameters and acceptable ranges, medications discontinued and newly started, any devices removed or remaining, current assessment baselines, anticipated trajectory, remaining concerns that warranted ICU level, and specific triggers for escalation back to ICU.","ICU-to-floor step-down transition handoff.","intermediate"),
  q("sq-bg16-68",ct,"critical_thinking_drills","A patient's serum osmolality gap is elevated.","What does an osmolal gap suggest?","Osmolal gap (measured minus calculated osmolality) >10 suggests unmeasured osmoles: toxic alcohols (methanol, ethylene glycol, isopropanol), mannitol, or severe hyperproteinemia. In a patient with metabolic acidosis and elevated osmolal gap, toxic alcohol ingestion should be suspected until proven otherwise. This requires emergent management with fomepizole and possible hemodialysis.","Osmolal gap toxic alcohol suspicion.","advanced"),
  q("sq-bg16-69",pd,"advocacy","A patient is being discharged to an unsafe home environment.","How would you advocate against unsafe home discharge?","I would document specific safety concerns: 'Patient requires 24-hour supervision due to fall risk and cognitive impairment. Home assessment reveals: multiple trip hazards, no bathroom modifications, primary caregiver works full-time, and patient cannot safely manage medications independently. I recommend skilled nursing facility placement or comprehensive home modification before discharge.'","Unsafe home discharge clinical documentation advocacy.","intermediate"),
  q("sq-bg16-70",cn,"career_advancement","You want to understand how to sustain a long nursing career.","How would you build a sustainable nursing career?","Long-term sustainability requires: regular self-assessment and specialty changes when needed, continuous education that keeps practice fresh, leadership development, work-life boundary maintenance, physical health prioritization, emotional support systems, financial planning for career flexibility, and remembering why you chose nursing. The nurses who last longest are those who evolve with the profession.","Sustainable career longevity strategy.","beginner"),
  q("sq-bg16-71",ip,"clinical_judgment","A patient develops rhabdomyolysis.","How would you manage rhabdomyolysis?","Rhabdomyolysis causes CK elevation >5x normal, myoglobinuria (dark brown urine), hyperkalemia, and AKI from myoglobin precipitation in renal tubules. I would administer aggressive IV NS (200-300 mL/hr initially), monitor urine output (target >200 mL/hr), check CK and electrolytes every 6 hours, treat hyperkalemia, and anticipate possible dialysis for severe cases.","Rhabdomyolysis aggressive hydration with urine output targets.","intermediate"),
  q("sq-bg16-72",ws,"patient_safety","A patient develops ventricular tachycardia with a pulse.","How would you manage stable VTach?","Stable VTach (patient conscious, adequate blood pressure) requires: continuous monitoring, IV amiodarone 150mg over 10 minutes, preparing for possible cardioversion, correcting electrolytes (K >4, Mg >2), and identifying the underlying cause (ischemia, electrolyte imbalance, drug toxicity). If the patient becomes unstable, immediately proceed to synchronized cardioversion.","Stable VTach amiodarone with cardioversion readiness.","intermediate"),
  q("sq-bg16-73",ct,"documentation_challenges","You need to document patient refusal of care.","How would you document a care refusal comprehensively?","I would document: specific care refused, reason stated by patient, patient's capacity to make the decision, risks of refusal explained (specific consequences), patient's verbalized understanding of risks, alternatives offered, physician notification, and patient's final decision. I would not use judgmental language. Patient refusal documentation protects both the patient and the nurse legally.","Care refusal comprehensive legal documentation.","beginner"),
  q("sq-bg16-74",pd,"patient_communication","A patient's cognitive decline is affecting their ability to make decisions.","How would you communicate with a cognitively declining patient?","I would use simple sentences, one concept at a time, yes/no questions when possible, provide written reminders, use visual cues, maintain a calm and unhurried manner, and include the patient in discussions at their capacity level. Even with cognitive decline, patients deserve to participate in their care to the extent they are able.","Cognitive decline adapted communication.","beginner"),
  q("sq-bg16-75",cn,"career_advancement","You want to understand the importance of self-advocacy in nursing.","Why is self-advocacy essential for nurses?","Self-advocacy ensures: safe working conditions, adequate compensation for your expertise, professional development opportunities, appropriate workload distribution, protection from workplace abuse, and career trajectory alignment with your goals. Nurses who advocate for themselves model the advocacy they provide for patients. Self-advocacy is not selfish—it is professional.","Self-advocacy as professional practice.","beginner"),
  q("sq-bg16-76",ip,"clinical_judgment","A patient develops acute coronary syndrome.","How would you differentiate STEMI from NSTEMI?","STEMI shows ST elevation on ECG indicating complete coronary occlusion requiring emergent PCI (door-to-balloon <90 minutes). NSTEMI shows ST depression or T-wave changes with elevated troponin indicating partial occlusion. Both require anticoagulation, antiplatelets, and cardiology consultation, but STEMI is more time-sensitive. I would obtain 12-lead ECG within 10 minutes of chest pain onset.","STEMI versus NSTEMI differentiation with time targets.","intermediate"),
  q("sq-bg16-77",ws,"interdisciplinary_communication","A patient's care plan needs revision after a family conference.","How would you update the care plan after a family meeting?","I would document decisions made during the meeting, update the care plan to reflect new goals, communicate changes to all nursing staff through handoff and the care plan, ensure orders match the new plan, update code status if changed, and verify that all team members are aligned with the revised approach. Care plan updates after conferences prevent contradictory care.","Post-conference care plan comprehensive update.","beginner"),
  q("sq-bg16-78",ct,"critical_thinking_drills","A patient's NT-proBNP is trending upward over three days.","What does a rising NT-proBNP trend indicate?","Rising NT-proBNP trend indicates worsening cardiac wall stress—heart failure is decompensating. I would assess for increasing fluid overload (weight gain, edema, crackles, orthopnea), review diuretic effectiveness, check fluid and sodium intake, and notify the provider. NT-proBNP trending is more useful than single values for guiding heart failure treatment adjustments.","NT-proBNP trending for HF decompensation.","intermediate"),
  q("sq-bg16-79",pd,"ethical_dilemmas","You witness research data being manipulated.","How would you handle research misconduct?","I would document the specific observations without confronting the researcher directly, report to the principal investigator and IRB, contact the research integrity officer, and preserve any evidence of data manipulation. Research misconduct endangers future patients who may receive treatments based on falsified data. Whistleblower protections exist for reporting research fraud.","Research misconduct proper reporting.","intermediate"),
  q("sq-bg16-80",cn,"career_advancement","You want to leave the nursing profession better than you found it.","How can every nurse contribute to advancing the profession?","Every nurse advances the profession by: providing excellent care daily, mentoring students and new nurses, participating in quality improvement, staying current with evidence-based practice, advocating for patients and colleagues, supporting nursing research, engaging in policy advocacy, and maintaining the public trust that makes nursing the most respected profession. Professional advancement starts at the bedside.","Individual nursing profession advancement.","beginner"),
  q("sq-bg16-81",ip,"clinical_judgment","A patient develops distributive shock from anaphylaxis.","How would you manage anaphylactic shock?","Anaphylactic shock requires: epinephrine 0.3-0.5mg IM (anterolateral thigh) immediately—this is the FIRST-LINE treatment, not antihistamines. Then: maintain airway, high-flow oxygen, IV crystalloid bolus, diphenhydramine and methylprednisolone as adjuncts, and repeat epinephrine every 5-15 minutes if needed. Monitor for biphasic reaction (recurrence 4-12 hours later). Position supine with legs elevated.","Anaphylaxis epinephrine-first with biphasic monitoring.","intermediate"),
  q("sq-bg16-82",ws,"patient_safety","A patient develops hospital-acquired venous thromboembolism.","How would you recognize hospital-acquired DVT?","DVT presents with unilateral leg swelling, pain, warmth, and positive Homan's sign (unreliable). I would measure bilateral calf circumferences for comparison, check D-dimer, and prepare for duplex ultrasound confirmation. Prevention failures should be investigated: was prophylaxis ordered? Was it administered? Were SCDs applied? Hospital-acquired VTE is a preventable sentinel event.","Hospital-acquired DVT recognition with prevention audit.","beginner"),
  q("sq-bg16-83",ct,"first_shift","You are managing your first unstable patient.","How would you approach your first unstable patient?","I would stay calm and systematic: assess ABCs, call for help early (rapid response team), communicate using SBAR, prepare for escalation, and trust my training. I would not try to manage instability alone—calling for help is the right decision. After the event, I would debrief with my preceptor and process the experience constructively.","First unstable patient systematic approach.","beginner"),
  q("sq-bg16-84",pd,"professional_boundaries","A patient's family brings you home-cooked food.","How would you handle a food gift from a family?","I would accept modestly: 'Thank you so much—that is very kind. I will share it with the team.' Small food gifts are generally acceptable and refusing them could damage the therapeutic relationship and cultural sensitivity. I would share with colleagues and express gratitude. This differs from monetary gifts, which should be declined.","Food gift gracious acceptance with team sharing.","beginner"),
  q("sq-bg16-85",cn,"performance_evaluation","You want to receive actionable feedback from your evaluation.","How would you elicit specific feedback during your evaluation?","I would ask targeted questions: 'Can you give me a specific example of when my assessment skills were strong? Where specifically have you seen me struggle? What one thing would make the biggest difference in my performance? What does successful independent practice look like to you in the next 3 months?' Specific questions yield specific, actionable feedback.","Specific feedback solicitation techniques.","beginner"),
  q("sq-bg16-86",ip,"clinical_judgment","A patient develops Boerhaave syndrome.","How would you manage esophageal perforation?","Boerhaave syndrome (spontaneous esophageal perforation from forceful vomiting) presents with Mackler's triad: vomiting, chest pain, and subcutaneous emphysema. CT shows pneumomediastinum. This is a surgical emergency with 50% mortality if delayed >24 hours. I would keep NPO, administer broad-spectrum antibiotics, provide IV fluids, and prepare for emergent thoracic surgery consultation.","Esophageal perforation time-critical surgical management.","advanced"),
  q("sq-bg16-87",ws,"delegation","You need to delegate monitoring a patient with increased fall risk.","How would you delegate enhanced fall prevention?","I would specify: 'Mrs. Williams is a high fall risk due to postural hypotension and confusion. Please round on her every 30 minutes, ensure the bed alarm is active, the bed is in the lowest position, non-skid socks are on, and the call light is within reach. Accompany her to the bathroom—she should not walk alone. Report any confusion changes to me.'","Enhanced fall prevention monitoring delegation.","beginner"),
  q("sq-bg16-88",ct,"critical_thinking_drills","A patient's bicarbonate is 14 mEq/L.","What does a low bicarbonate indicate?","Bicarbonate of 14 (normal 22-26) indicates metabolic acidosis—bicarbonate is consumed buffering excess acid. Causes include: DKA, lactic acidosis, renal failure, toxic ingestion, and severe diarrhea (bicarbonate loss). I would calculate the anion gap to differentiate causes, check pH and PCO2 for respiratory compensation, and address the underlying etiology.","Low bicarbonate metabolic acidosis with anion gap calculation.","beginner"),
  q("sq-bg16-89",pd,"advocacy","A patient needs glasses but cannot afford them.","How would you help a patient access vision correction?","I would involve social work, research vision assistance programs (Lions Club provides free eyeglasses, Prevent Blindness, VSP Eyes of Hope), check Medicaid coverage for vision services, explore community health center vision clinics, and ensure the patient can read their discharge instructions and medication labels—poor vision is a medication safety issue.","Vision access advocacy as safety concern.","beginner"),
  q("sq-bg16-90",cn,"career_advancement","You want to be a lifelong learner in nursing.","How would you cultivate lifelong learning in nursing?","I would set annual learning goals, subscribe to nursing journals, attend professional conferences, pursue certifications, participate in journal clubs, seek diverse clinical experiences, embrace new technology, learn from every patient encounter, and maintain curiosity about why things work the way they do. The moment a nurse stops learning is the moment they start becoming obsolete.","Lifelong learning cultivation strategy.","beginner"),
  q("sq-bg16-91",ip,"clinical_judgment","A patient develops ventricular fibrillation.","How would you manage VFib arrest?","VFib requires immediate defibrillation—this is the most time-sensitive intervention. I would start high-quality CPR, defibrillate at 200J biphasic as soon as the defibrillator is available, resume CPR immediately after shock for 2 minutes before rhythm check, administer epinephrine after the second shock, and amiodarone 300mg IV after the third shock if VFib persists.","VFib ACLS with defibrillation priority.","advanced"),
  q("sq-bg16-92",ws,"patient_safety","A patient is at risk for falls during toileting.","How would you prevent toileting-related falls?","Toileting falls are the most common hospital fall type. I would proactively offer toileting assistance during rounds, ensure the call light is within reach, provide non-skid socks, keep the pathway clear and lit, use a bedside commode for high-risk patients, maintain bed in lowest position, and never rush a patient during transfers. Anticipatory toileting assistance prevents the urgency that causes falls.","Toileting fall prevention proactive strategy.","beginner"),
  q("sq-bg16-93",ct,"documentation_challenges","You need to document a patient's functional status for discharge.","How would you document functional status for discharge planning?","I would document: mobility level (ambulates independently, with device, or requires assistance), ADL capabilities (bathing, dressing, toileting, feeding), cognitive function for medication management, home environment assessment findings, caregiver availability and capability, equipment needs, and therapy recommendations. Functional documentation drives appropriate discharge disposition.","Functional status discharge documentation.","beginner"),
  q("sq-bg16-94",pd,"patient_communication","A patient asks about their realistic recovery expectations.","How would you set realistic recovery expectations?","I would be honest while encouraging: 'Recovery from your surgery typically takes 6-8 weeks. The first two weeks are the hardest—you will need help at home. By week 4, most patients resume light activities. Full recovery varies by individual. I want to set realistic expectations so you do not get discouraged by normal recovery challenges.'","Realistic recovery timeline communication.","beginner"),
  q("sq-bg16-95",cn,"career_advancement","You want to understand the value of professional writing.","Why should nurses develop professional writing skills?","Professional writing enables: publishing case studies and research, contributing to nursing journals, developing patient education materials, writing policy proposals, creating effective incident reports, communicating through professional channels, and establishing expertise. Strong writing skills differentiate nurses for leadership, education, and advanced practice roles.","Professional writing career value.","beginner"),
  q("sq-bg16-96",ip,"clinical_judgment","A patient develops acute kidney injury from contrast.","How would you monitor for contrast-induced nephropathy?","I would check baseline creatinine before contrast administration, ensure adequate pre-hydration, monitor creatinine at 24 and 48 hours post-contrast, assess urine output, hold metformin for 48 hours, and compare post-contrast creatinine to baseline. CIN typically develops within 24-72 hours and peaks at 3-5 days. Most cases resolve within 1-2 weeks.","CIN monitoring timeline and metformin hold.","intermediate"),
  q("sq-bg16-97",ws,"medication_error","A patient on multiple anticoagulants develops bleeding.","How would you manage multi-anticoagulant bleeding?","I would identify all anticoagulants the patient is receiving, hold all anticoagulant therapy, apply direct pressure to visible bleeding, check coagulation studies, administer appropriate reversal agents based on the specific agents involved, prepare for possible blood product transfusion, and investigate why the patient was on multiple anticoagulants simultaneously.","Multi-anticoagulant bleeding management.","advanced"),
  q("sq-bg16-98",ct,"new_nurse_anxiety","You are afraid of making decisions independently.","How would you build decision-making confidence?","I would start with decisions I am confident about and gradually expand, use clinical reasoning frameworks for complex decisions, verify critical decisions with a colleague until confident, reflect on outcomes of previous decisions (most were correct), and remember that appropriate escalation is itself a good decision. Confidence grows through accumulated successful decisions.","Decision-making confidence gradual building.","beginner"),
  q("sq-bg16-99",pd,"ethical_dilemmas","You are asked to care for a patient involved in a violent crime.","How would you provide care to a perpetrator of violence?","I would provide the same standard of care regardless of the patient's alleged actions. My role is not to judge—it is to heal. I would maintain professional boundaries, ensure safety measures are in place, manage my emotional response through debriefing, and remember that every patient retains human dignity and the right to medical care. Justice is not my responsibility as a nurse.","Non-judgmental perpetrator care commitment.","intermediate"),
  q("sq-bg16-100",cn,"career_advancement","You want to reflect on why nursing matters.","Why does nursing matter?","Nursing matters because nurses are present for humanity's most vulnerable moments: birth, death, illness, and recovery. We translate medical complexity into human understanding, advocate when patients cannot speak for themselves, prevent harm through vigilance, comfort when curing is not possible, and provide the continuous presence that defines the healing environment. Nursing is not just a career—it is a calling to serve.","Nursing significance reflection.","beginner"),
];
